#![allow(unused_imports)]
use std::io;
use std::cmp::*;
use std::collections::*;
#[allow(dead_code)]
const M: i64 = 1e9 as i64 + 7;

fn read_line() -> String {
    let stdin = io::stdin();
    let mut buf = String::new();
    stdin.read_line(&mut buf).unwrap();
    buf
}
#[allow(dead_code)]
fn read<T>() -> T where T: std::str::FromStr, T::Err : std::fmt::Debug {
    read_line().trim().parse().unwrap()
}
#[allow(dead_code)]
fn readv<T>() -> Vec<T> where T: std::str::FromStr, T::Err : std::fmt::Debug {
    read_line().split(' ').map(|a| a.trim().parse().unwrap()).collect()
}

fn get_diff(n: i64) -> i64{
    let mut diff = n;
    for i in 0..19 {
        diff -= n / 10i64.pow(i) % 10;
    }
    diff
}

fn main() {
    let input = readv::<i64>();
    let (n, s) = (input[0], input[1]);
    let mut num = n;
    if get_diff(n) < s {
        println!("{}", 0);
        return;
    }
    for i in (1..19).rev() {
        let p = 10i64.pow(i);
        loop {
            num -= p;
            if get_diff(num) < s {
                num += p;
                break;
            }
        }
    }
    num = num / 10 * 10;
    println!("{}", n - num + 1);
}
